import React, { useContext } from 'react';
import { Container } from 'react-bootstrap'; 
import { Link } from 'react-router-dom';
// Importaciones de Contextos necesarias para el logo
import { SettingsContext } from '../context/SettingsContext'; 
// Importamos el componente que vamos a probar
import SearchBox from './SearchBox'; 

const Header = () => {
  const { settings } = useContext(SettingsContext);

  // CLASES CRÍTICAS:
  // - w-full sticky top-0 z-50 para que flote
  // - No se añade ninguna clase de rounded, el Header debe ser recto.
  
  return (
    <header 
      className="w-full sticky top-0 z-50 transition-all duration-300 shadow-md"
      style={{ backgroundColor: 'var(--brand-dark)' }} 
    >
      <Container className="py-3"> 
        {/* CRÍTICO: d-flex y justify-content-between para alinear Logo, Search y Acciones */}
        <div className="d-flex justify-content-between align-items-center">
          
          {/* 1. Logo / Nombre del Sitio (Izquierda) */}
          <Link 
            to="/" 
            // Establece un ancho fijo para el logo para que el buscador se centre mejor
            className="text-gray-300 no-underline hover:text-white transition-colors flex flex-col items-start h-full w-40 flex-shrink-0"
          > 
            <span 
              className="text-white text-xl font-extrabold tracking-widest uppercase" 
              style={{ lineHeight: 1 }}
            >
              {settings?.siteName || 'TECNOTITLÁN'}
            </span>
            <span 
              className="text-gray-400 text-xs font-light tracking-wide mt-0.5" 
              style={{ lineHeight: 1 }} 
            >
              Tecnología con Raíces
            </span>
          </Link>

          {/* 2. Barra de búsqueda (Centrada, solo Desktop) */}
          {/* w-1/2 max-w-lg mx-auto para centrar y ocupar el espacio restante */}
          <div className="d-none d-lg-block w-1/2 max-w-lg mx-auto px-5">
            <SearchBox /> 
          </div>
          
          {/* 3. Navegación Derecha (Mockup de espacio vacío) */}
          {/* Usamos un div con el mismo ancho del logo para forzar la simetría */}
          <div className="w-40 flex-shrink-0">
             {/* Aquí irían los iconos de Carrito y Usuario */}
          </div>

        </div>
        
        {/* FILA 2: Barra de búsqueda (Solo Móvil - Se extiende en su propia fila) */}
        <div className="d-lg-none mt-3">
          <SearchBox />
        </div>
      </Container>
    </header>
  );
};

export default Header;
